// Pull the reply down to clean fields. Handles n8n Gmail trigger output shapes.
return $input.all().map(function (it) {
  const m = it.json;
  const fromRaw = String(m.from || m.From || m.sender || '');
  const br = fromRaw.match(/<([^>]+)>/);
  const from_email = (br ? br[1] : fromRaw).trim().toLowerCase();
  return { json: {
    from_email: from_email,
    reply_subject: String(m.subject || m.Subject || ''),
    reply_body: String(m.text || m.textPlain || m.textHtml || m.body || m.snippet || '').slice(0, 6000),
    reply_message_id: m.id || '',
    reply_thread_id: m.threadId || '',
  } };
});

// Gate: only process replies from a prospect we are mid-conversation with.
// Then fetch Layer 1 brain and build the reply-classifier request.
const rows = $input.all();
if (rows.length === 0) return [];
const row = rows[0].json;
const reply = $('Extract Reply').first().json;

const status = String(row.status || '').trim().toLowerCase();
const active = ['opener_sent', 'teardown_sent', 'nudged'];
if (!row.prospect_id || active.indexOf(status) === -1) return [];
const stage = status === 'teardown_sent' ? 'after_teardown' : 'after_opener';

const repo = 'https://raw.githubusercontent.com/isaiahwong-bit/Digital-Artifacts';
const refs = ['main', 'feat/sales-ops-automation'];
const files = ['outbound-offer', 'company-brief', 'pricing', 'tone-of-voice'];
const brain = {};
for (const f of files) {
  let got = null;
  for (const ref of refs) {
    try {
      got = await this.helpers.httpRequest({ method: 'GET', url: repo + '/' + ref + '/brain/' + f + '.md', encoding: 'text', json: false });
      break;
    } catch (e) { got = null; }
  }
  if (got === null) throw new Error('Brain file unreachable on any branch: ' + f);
  brain[f] = got;
}

const classifierSystem = 'You are the Digital Artifacts reply-classifier (Layer 2 skill). You classify a reply to a Digital Artifacts outbound email. Be conservative: when unsure between proceeding and stopping, stop. Any opt-out always wins over any other reading. Return strictly the JSON schema, nothing else, no prose, no markdown fences.';
const classSchema = '{"intent":"interested|question|not_now|not_interested|unsubscribe|auto_reply|unclear","task_description":"if they gave a task to tear down, the task in one clean sentence, else empty","wants_second_freebie":true|false,"sentiment":"warm|neutral|negative","recommended_action":"send_teardown|answer_question|route_to_booking|suppress|human_review|ignore","reason":"one sentence"}';
const content = '<offer>\n' + brain['outbound-offer'] + '\n</offer>\n\n'
  + '<context>\nStage: ' + stage + '\nProspect: ' + (row.contact_name || row.business_name || '') + ' at ' + (row.business_name || '') + '\n</context>\n\n'
  + '<reply>\n' + (reply.reply_subject || '') + '\n' + (reply.reply_body || '') + '\n</reply>\n\n'
  + 'Return strictly this JSON, nothing else:\n' + classSchema;
const classifier_body = { model: 'claude-sonnet-4-6', max_tokens: 500, system: classifierSystem, messages: [{ role: 'user', content: content }] };

return [{ json: { ...row, ...reply, stage: stage, brain: brain, classifier_body: classifier_body } }];

// Parse the classifier verdict, set the route, prebuild the teardown request + Telegram texts.
const prev = $('Gate + Classify Prep').first().json;
const raw = ($json && $json.content && $json.content[0] && $json.content[0].text) || '';
let c;
try { const s = raw.indexOf('{'); const e = raw.lastIndexOf('}'); c = JSON.parse(raw.slice(s, e + 1)); }
catch (err) {
  c = { intent: 'unclear', task_description: '', wants_second_freebie: false, sentiment: 'neutral', recommended_action: 'human_review', reason: 'Classifier response could not be parsed.' };
}

const ra = c.recommended_action || 'human_review';
let route;
if (ra === 'send_teardown' && c.task_description) route = 'teardown';
else if (ra === 'suppress') route = 'suppress';
else if (ra === 'ignore') route = 'ignore';
else route = 'flag';

const b = prev.brain || {};
const teardownSystem = 'You are writing a free, personalised automation teardown from Isaiah at Digital Artifacts (Layer 2 skill: teardown-writer). It earns trust by being genuinely good and genuinely honest. If the task is not worth automating, say so plainly and stop there with goodwill. HARD RULES: no em dashes ever, plain language, no invented clients or statistics, sign off Isaiah only, max around 350 words in body_plain excluding the footer. One soft next step near the end: invite them to reply to set up 15 minutes to scope it, no booking link, no urgency. End body_plain with the token {{ SENDER_FOOTER }} on its own final line. Return JSON only, no prose, no markdown fences.';
const tdSchema = '{"subject":"references their task, not our framework","body_plain":"the one-page teardown, plain text, ends with {{ SENDER_FOOTER }} on its own final line","verdict":"worth_automating|partially|not_worth_it","honest_caveat":"the single most important thing that could make this not work","confidence":"high|medium|low","notes_for_isaiah":"one sentence on the call you made and why"}';
const tdContent = '<offer>\n' + (b['outbound-offer'] || '') + '\n</offer>\n\n'
  + '<company>\n' + (b['company-brief'] || '') + '\n</company>\n\n'
  + '<pricing>\n' + (b['pricing'] || '') + '\n</pricing>\n\n'
  + '<tone>\n' + (b['tone-of-voice'] || '') + '\n</tone>\n\n'
  + '<prospect>\nBusiness: ' + (prev.business_name || '') + '\nContact: ' + (prev.contact_name || '') + ' (' + (prev.contact_role || '') + ')\nArchetype: ' + (prev.archetype || '') + '\n</prospect>\n\n'
  + '<their_task>\n' + (c.task_description || prev.reply_body || '') + '\n</their_task>\n\n'
  + 'Write the teardown. Return strictly this JSON, nothing else:\n' + tdSchema;
const teardown_body = { model: 'claude-sonnet-4-6', max_tokens: 1200, system: teardownSystem, messages: [{ role: 'user', content: tdContent }] };

const replyShort = String(prev.reply_body || '').slice(0, 1500);
const flag_text = ('REPLY NEEDS YOU - ' + (prev.business_name || '') + '\n\n'
  + 'Intent: ' + (c.intent || '') + ' / ' + ra + '\n'
  + 'Why: ' + (c.reason || '') + '\n\n'
  + 'From: ' + (prev.email || prev.from_email || '') + '\n'
  + 'Subject: ' + (prev.reply_subject || '') + '\n\n'
  + replyShort).slice(0, 3900);
const supp_text = ('OPT-OUT - ' + (prev.business_name || '') + ' (' + (prev.email || prev.from_email || '') + ')\n'
  + 'Reply read as: ' + (c.intent || '') + '. Added to suppression, will not be contacted again.').slice(0, 3900);
const supp_status = c.intent === 'unsubscribe' ? 'unsubscribed' : 'suppressed';

return [{ json: { ...prev, classification: c, route: route, teardown_body: teardown_body, flag_text: flag_text, supp_text: supp_text, supp_status: supp_status } }];

// Parse the teardown, inject the compliance footer, build the sheet row + Telegram brief.
const prev = $('Parse Classification + Teardown Prep').first().json;
const raw = ($json && $json.content && $json.content[0] && $json.content[0].text) || '';
let td;
try { const s = raw.indexOf('{'); const e = raw.lastIndexOf('}'); td = JSON.parse(raw.slice(s, e + 1)); }
catch (err) {
  td = { subject: '', body_plain: '', verdict: '', honest_caveat: '', confidence: 'low', notes_for_isaiah: 'Teardown response could not be parsed. Do not approve, regenerate this one.' };
}

const unsubUrl = 'https://digitalartifacts.com.au/unsubscribe?id=' + encodeURIComponent(prev.prospect_id || '') + '&list=outbound';
const footer = '\nDigital Artifacts, Sydney NSW, Australia. Sent by Isaiah Wong, isaiah@digitalartifacts.com.au\n'
  + 'Not interested? Reply with the word unsubscribe, or use this link: ' + unsubUrl + '. You will be removed straight away.';
let body = String(td.body_plain || '');
if (body.indexOf('{{ SENDER_FOOTER }}') !== -1) body = body.split('{{ SENDER_FOOTER }}').join(footer);
else if (body.indexOf('{{SENDER_FOOTER}}') !== -1) body = body.split('{{SENDER_FOOTER}}').join(footer);
else body = body.replace(/\s*$/, '') + '\n' + footer;
body = body.replace(/—|–/g, ',');
td.body_plain = body;

const now = new Date().toISOString();
const business = prev.business_name || '';
const tg_text = ('TEARDOWN READY for approval - ' + business + '\n\n'
  + 'Verdict: ' + (td.verdict || '') + ' (' + (td.confidence || '') + ' confidence)\n\n'
  + 'Subject: ' + (td.subject || '') + '\n\n'
  + String(td.body_plain || '').slice(0, 2600) + '\n\n-------\n'
  + (td.notes_for_isaiah || 'No notes.')).slice(0, 3900);

return [{ json: {
  prospect_id: prev.prospect_id,
  business_name: business,
  email: prev.email || prev.from_email || '',
  teardown_subject: td.subject || '',
  teardown_body: td.body_plain || '',
  reply_task: (prev.classification && prev.classification.task_description) || '',
  now: now,
  tg_text: tg_text,
} }];
